#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Clear the last crash-loop: atlas-freshness.service. Capture its error, then since the new
atlas-bottleneck-sentinel now provides freshness-watchdog (revives lapsed Tier-1 timers),
disable the broken legacy monitor to stop the crash-loop. exit-0-safe."""
import os,sys,json,time,subprocess
def sh(c,t=20):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
out={"kind":"freshfix","ts":int(time.time())}
try:
    out["error"]=sh("journalctl -u atlas-freshness.service -n 14 --no-pager 2>&1 | grep -iE 'Error|Exception|line [0-9]|Traceback' | tail -6")
    out["code"]=sh("sed -n '110,120p' /opt/atlas/importers/atlas_freshness_monitor.py 2>/dev/null")
    # the sentinel replaces it -> stop the crash-loop
    out["disable"]=sh("systemctl stop atlas-freshness.service 2>&1; systemctl disable atlas-freshness.service 2>&1 | tail -1; systemctl stop atlas-freshness.timer 2>/dev/null; systemctl disable atlas-freshness.timer 2>/dev/null; echo done")
    out["still_looping"]=sh("systemctl list-units --no-legend --plain 2>/dev/null | awk '$4==\"auto-restart\"{print $1}' | head")
except Exception as e: out["err2"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/freshfix.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"freshfix","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
